for code, tr in languages.items():
    res = html.replace('lang="en"', f'lang="{tr["lang"]}"')
    res = res.replace('<title>PageGuides — Free SEO Microtools</title>', f'<title>{tr["title"]}</title>')
    res = res.replace('content="Free and fast SEO tools. Analyze keywords, generate slugs, preview Open Graph, validate robots.txt and much more."', f'content="{tr["desc"]}"')
    res = res.replace('<span class="nav-tag" style="display: none;">Premium SEO Tools</span>', f'<span class="nav-tag" style="display: none;">{tr["tag"]}</span>')
    res = res.replace('60 Tools · 100% Free', tr['hero_badge'])
    res = res.replace('<em>Fast</em>, no-signup SEO microtools', tr['hero_title'])
    res = res.replace('Everything you need to optimize your content, structure your site, and master metadata. With a premium visual experience.', tr['hero_desc'])
    res = res.replace('Content Analysis', tr['cat1'])
    res = res.replace('On-Page SEO & Metadata', tr['cat2'])
    res = res.replace('Technical SEO & Structure', tr['cat3'])
    res = res.replace('Campaign Analytics', tr['cat4'])
    res = res.replace('AI & Advanced Content', tr['cat5'])
    res = res.replace('Rich Results & Social', tr['cat6'])
    res = res.replace('Advanced Technical SEO', tr['cat7'])
    res = res.replace('Advanced Site Management', tr['cat8'])
    res = res.replace('Marketing & Growth', tr['cat8'])
    res = res.replace('Competitive Productivity', tr['cat9'])
    res = res.replace('Open tool →', tr['open_tool'])
    res = res.replace('NEW', tr['new'])
    
    # tools
    for en_name, (tr_name, tr_desc) in tr['tools'].items():
        res = re.sub(rf'<div class="tool-name">{en_name}</div>\s*<div class="tool-desc">.*?</div>', f'<div class="tool-name">{tr_name}</div>\\n                    <div class="tool-desc">{tr_desc}</div>', res, flags=re.DOTALL)
    
    # dropdown button
    res = re.sub(r'<span class="lang-flag">🇺🇸</span> EN', tr['dropdown'], res)
    
    # fix relative paths to tools
    res = res.replace('href="/" class="logo"', f'href="/{code}/" class="logo"')
    # all local hrefs
    res = re.sub(r'href="([^/][^"]+\.html)"', r'href="\1"', res) # leave them pointing to local file (e.g. href="keyword-density.html" -> keyword-density.html which is /es/keyword-density.html)
    
    # also the logic for hover active state in dropdown
    res = res.replace('<a href="/" class="lang-option active"><span class="lang-flag">🇺🇸</span> English</a>', '<a href="/" class="lang-option"><span class="lang-flag">🇺🇸</span> English</a>')
    
    if code == 'es':
        res = res.replace('<a href="/es/" class="lang-option"><span class="lang-flag">🇪🇸</span> Español</a>', '<a href="/es/" class="lang-option active"><span class="lang-flag">🇪🇸</span> Español</a>')
    elif code == 'fr':
        res = res.replace('<a href="/fr/" class="lang-option"><span class="lang-flag">🇫🇷</span> Français</a>', '<a href="/fr/" class="lang-option active"><span class="lang-flag">🇫🇷</span> Français</a>')
    elif code == 'pt':
        res = res.replace('<a href="/pt/" class="lang-option"><span class="lang-flag">🇧🇷</span> Português</a>', '<a href="/pt/" class="lang-option active"><span class="lang-flag">🇧🇷</span> Português</a>')
    elif code == 'hi':
        res = res.replace('<a href="/hi/" class="lang-option"><span class="lang-flag">🇮🇳</span> हिन्दी</a>', '<a href="/hi/" class="lang-option active"><span class="lang-flag">🇮🇳</span> हिन्दी</a>')
        
    os.makedirs(f'/Users/franciscoinfante/Downloads/oneusepage/pageguides.com/{code}', exist_ok=True)
    with open(f'/Users/franciscoinfante/Downloads/oneusepage/pageguides.com/{code}/index.html', 'w', encoding='utf-8') as f:
        f.write(res)
        
